// ===================
// Translate Interface
// ===================

// Translate manages translation models and their configuration.
type Translate interface {
	// GetTranslationModels lists all available translation models.
	GetTranslationModels(context.Context, *GetTranslationModelsRequest) (*GetTranslationModelsResponse, error)

	// ConfigureGenerativeTranslator creates or updates a generative translation
	// model configuration.
	ConfigureGenerativeTranslator(context.Context, *ConfigureGenerativeTranslatorRequest) (*ConfigureGenerativeTranslatorResponse, error)

	// RemoveGenerativeTranslator removes a generative translation model
	// configuration.
	RemoveGenerativeTranslator(context.Context, *RemoveGenerativeTranslatorRequest) (*RemoveGenerativeTranslatorResponse, error)

	// TranslateDocument translates the content of a document to a target
	// language. Returns the translated document with original content
	// preserved in a meta block.
	TranslateDocument(context.Context, *TranslateDocumentRequest) (*TranslateDocumentResponse, error)
}

